import Box from '@mui/material/Box'
import Typography from '@mui/material/Typography'
import { Icon } from '@iconify/react'
import SectionHeading from '../ui/SectionHeading'
import { EVERYTHING } from '../data/landing.data'

function CenterCard() {
  return (
    <Box
      sx={{
        backgroundColor: '#0B0B0F',
        borderRadius: 'var(--radius-lg)',
        p: { xs: 2.5, md: 3 },
        color: '#FFFFFF',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
        gap: 2,
        minHeight: 220,
        transform: 'rotate(-2deg)',
        boxShadow: 'var(--shadow-card), 0 12px 30px rgba(251,201,66,0.18)',
      }}
    >
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.25 }}>
        <Box
          sx={{
            width: 32,
            height: 32,
            borderRadius: '8px',
            backgroundColor: 'var(--brand-primary)',
            display: 'inline-flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: '#1F1F1F',
            fontWeight: 800,
            fontSize: '0.875rem',
          }}
        >
          G
        </Box>
        <Box>
          <Typography sx={{ fontWeight: 800, fontSize: '0.8125rem', letterSpacing: '0.06em' }}>GROWVE</Typography>
          <Typography sx={{ fontSize: '0.5625rem', color: 'rgba(255,255,255,0.65)', letterSpacing: '0.22em', fontWeight: 600 }}>
            LOGISTICS
          </Typography>
        </Box>
      </Box>

      <Box>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Typography variant='Heading/H5-Bold' sx={{ color: '#FFFFFF' }}>
            {EVERYTHING.centerCard.title}
          </Typography>
          <Icon icon='mdi:truck-fast-outline' fontSize={20} color='#FBC942' />
        </Box>
        <Typography variant='Body/S-Regular' sx={{ color: 'rgba(255,255,255,0.65)', mt: 1, lineHeight: 1.5 }}>
          {EVERYTHING.centerCard.description}
        </Typography>
      </Box>
    </Box>
  )
}

export default function EverythingSection() {
  // Render 3x3 grid; insert CenterCard at position [1,1] (index 4 in DOM order)
  const allCards = EVERYTHING.cards
  return (
    <Box className='landing-section' sx={{ backgroundColor: 'var(--surface-page)' }}>
      <Box className='landing-container'>
        <SectionHeading
          eyebrow={EVERYTHING.eyebrow}
          title={EVERYTHING.titleLeading}
          accent={EVERYTHING.titleAccent}
          subtitle={EVERYTHING.subtitle}
          size='md'
        />

        <Box
          sx={{
            mt: { xs: 5, md: 7 },
            display: 'grid',
            gridTemplateColumns: { xs: '1fr', sm: 'repeat(2, 1fr)', md: 'repeat(3, 1fr)' },
            gap: 2.5,
          }}
        >
          {allCards.slice(0, 4).map((card) => (
            <FeatureCard key={card.title} title={card.title} description={card.description} />
          ))}
          <Box sx={{ display: { xs: 'none', md: 'block' } }}>
            <CenterCard />
          </Box>
          {allCards.slice(4).map((card) => (
            <FeatureCard key={card.title} title={card.title} description={card.description} />
          ))}
        </Box>
      </Box>
    </Box>
  )
}

function FeatureCard({ title, description }: { title: string; description: string }) {
  return (
    <Box
      sx={{
        backgroundColor: 'var(--surface-muted)',
        border: '1px solid var(--border-subtle)',
        borderRadius: 'var(--radius-lg)',
        p: { xs: 2.5, md: 3 },
        display: 'flex',
        flexDirection: 'column',
        gap: 2,
        minHeight: 220,
        cursor: 'pointer',
        transition: 'transform 0.2s ease, box-shadow 0.2s ease',
        '&:hover': {
          transform: 'translateY(-2px)',
          boxShadow: 'var(--shadow-soft)',
        },
      }}
    >
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 2 }}>
        <Typography variant='Heading/H5-Bold' sx={{ color: 'var(--text-strong)' }}>
          {title}
        </Typography>
        <Icon icon='mdi:arrow-right' fontSize={18} color='#1F1F1F' />
      </Box>
      <Typography variant='Body/S-Regular' sx={{ color: 'var(--text-secondary)', lineHeight: 1.6, mt: 'auto' }}>
        {description}
      </Typography>
    </Box>
  )
}
